import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API = "http://localhost:3000/api";
const FASALLADA = ["Xadaano", "1aad", "2aad", "3aad", "4aad", "5aad", "6aad", "7aad", "8aad", "9aad", "10aad", "11aad", "12aad"];
const DAYS = Array.from({ length: 31 }, (_, i) => i + 1);

export default function App() {
  const [user, setUser] = useState(null);
  const [allStudents, setAllStudents] = useState([]);
  const [view, setView] = useState("classes");
  const [activeFasal, setActiveFasal] = useState("");
  const [adminTab, setAdminTab] = useState("attendance");
  const [studentTab, setStudentTab] = useState("exam");
  const [form, setForm] = useState({ id: "", pass: "" });

  useEffect(() => { if (user?.role === 'admin') load(); }, [user]);
  const load = () => axios.get(`${API}/data`).then(res => setAllStudents(res.data));

  const login = () => {
    axios.post(`${API}/login`, form).then(res => setUser(res.data)).catch(() => alert("ID ama Pass waa khaldan yahay!"));
  };

  const sync = (data) => { setAllStudents(data); axios.post(`${API}/update`, data); };

  // XARAYNTA ARDAYGA CUSUB (XOG DHEERI AH)
  const addStudent = (f) => {
    const n = prompt("Magaca Saddexan:");
    const meel = prompt("Meesha uu ku dhashay:");
    const hooyoMagac = prompt("Magaca Hooyada:");
    const aaboTel = prompt("Lambarka Aabbaha:");
    const hooyoTel = prompt("Lambarka Hooyada:");
    const id = prompt("ID-ga uu ku galayo:");
    const pass = prompt("Password-ka ardayga (tusaale: 123):", "123");

    if(n && id) {
      const newStudent = { 
        id, pass, magaca: n, meel, hooyo: hooyoMagac, 
        aaboTel, hooyoTel, fasalka: f, exams: {}, att: {}, fee: "Ma bixin" 
      };
      sync([...allStudents, newStudent]);
    }
  };

  if (!user) return (
    <div style={st.loginBg}><div style={st.card}>
      <h1 style={{color:'#2c3e50', marginBottom:'5px'}}>NAWAWI SCHOOL</h1>
      <p style={{marginBottom:'20px', color:'#7f8c8d'}}>Maamulka Dugsiga</p>
      <input style={st.in} placeholder="Admin ID ama Student ID" onChange={e => setForm({...form, id: e.target.value})} />
      <input style={st.in} type="password" placeholder="Password" onChange={e => setForm({...form, pass: e.target.value})} />
      <button style={st.btn} onClick={login}>SOO GAL</button>
    </div></div>
  );

  return (
    <div style={{display:'flex', height:'100vh', background:'#f8f9fa'}}>
      {/* SIDEBAR */}
      <div style={st.sidebar}>
        <div style={st.profile}><h3>NAWAWI</h3><p>{user.magaca}</p></div>
        <div style={st.nav}>
          {user.role === 'admin' ? (
            <>
              <button style={st.navBtn} onClick={() => setView("classes")}>🏠 Dhammaan Fasallada</button>
              <button style={st.navBtn} onClick={() => setAdminTab("attendance")}>📅 Xadiris (√/X)</button>
              <button style={st.navBtn} onClick={() => setAdminTab("exams")}>📝 Imtixaanada</button>
              <button style={st.navBtn} onClick={() => setAdminTab("fees")}>💰 Lacagaha</button>
            </>
          ) : (
            <>
              <button style={st.navBtn} onClick={() => setStudentTab("exam")}>📊 Natiijada</button>
              <button style={st.navBtn} onClick={() => setStudentTab("attendance")}>📅 Xadiriska</button>
              <button style={st.navBtn} onClick={() => setStudentTab("fee")}>💵 Lacagta</button>
            </>
          )}
        </div>
        <button style={st.out} onClick={() => setUser(null)}>Logout</button>
      </div>

      {/* CONTENT AREA */}
      <div style={{flex:1, padding:'40px', overflowY:'auto'}}>
        {user.role === 'admin' ? (
          view === "classes" ? (
            <div style={st.grid}>
              {FASALLADA.map(f => (
                <div key={f} style={st.classBox} onClick={() => { setActiveFasal(f); setView("list"); }}>
                  <h3>{f}</h3>
                  <p>{allStudents.filter(s => s.fasalka === f).length} Arday</p>
                  <button style={st.addBtn} onClick={(e) => { e.stopPropagation(); addStudent(f); }}>+ Ku dar Arday</button>
                </div>
              ))}
            </div>
          ) : (
            <div style={st.whiteCard}>
              <button onClick={() => setView("classes")} style={st.backBtn}>← Back</button>
              <h2>{activeFasal} - {adminTab.toUpperCase()}</h2>
              <table style={st.table}>
                <thead><tr style={st.thead}><th>ID</th><th>Magaca</th><th>Dhalasho</th><th>Tel Waalid</th><th>Action</th></tr></thead>
                <tbody>
                  {allStudents.filter(s => s.fasalka === activeFasal).map(s => (
                    <tr key={s.id} style={st.tr}>
                      <td>{s.id}</td>
                      <td>{s.magaca}</td>
                      <td>{s.meel}</td>
                      <td style={{fontSize:'12px'}}>Aabo: {s.aaboTel}<br/>Hooyo: {s.hooyoTel}</td>
                      <td>
                        {adminTab === "attendance" && (
                          <div style={{display:'flex', gap:'5px', justifyContent:'center'}}>
                            <button style={st.pBtn} onClick={() => { s.att[new Date().getDate()] = "√"; sync([...allStudents]); }}>√</button>
                            <button style={st.aBtn} onClick={() => { s.att[new Date().getDate()] = "X"; sync([...allStudents]); }}>X</button>
                          </div>
                        )}
                        {adminTab === "exams" && <input placeholder="Score" style={st.miniIn} onBlur={(e) => { s.exams["Guud"] = e.target.value; sync([...allStudents]); }} />}
                        {adminTab === "fees" && <select value={s.fee} onChange={(e) => { s.fee = e.target.value; sync([...allStudents]); }}><option>Ma bixin</option><option>Bixiyey</option></select>}
                        <button onClick={() => sync(allStudents.filter(x => x.id !== s.id))} style={{color:'red', border:'none', background:'none', cursor:'pointer'}}>Del</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )
        ) : (
          /* STUDENT VIEW */
          <div style={st.stuCard}>
              <h1>Arday: {user.magaca}</h1>
              <div style={{display:'flex', gap:'20px', marginBottom:'20px'}}>
                  <div style={st.infoBox}><strong>Dhalasho:</strong> {user.meel}</div>
                  <div style={st.infoBox}><strong>Aabo Tel:</strong> {user.aaboTel}</div>
                  <div style={st.infoBox}><strong>Hooyo Tel:</strong> {user.hooyoTel}</div>
              </div>
              {studentTab === "attendance" && (
                  <div style={st.box}>
                      <h3>📅 Xadiriskaaga (Bishaan)</h3>
                      <div style={st.attGrid}>
                          {DAYS.map(d => (
                              <div key={d} style={{...st.dayBox, 
                                background: user.att[d] === "√" ? '#2ecc71' : user.att[d] === "X" ? '#e74c3c' : '#fff',
                                color: user.att[d] ? '#fff' : '#000'
                              }}>{d}<br/>{user.att[d] || "-"}</div>
                          ))}
                      </div>
                  </div>
              )}
              {studentTab === "exam" && <div style={st.box}><h3>📝 Natiijada: {user.exams["Guud"] || 0}</h3></div>}
              {studentTab === "fee" && <div style={st.box}><h3>💰 Lacagta: {user.fee}</h3></div>}
          </div>
        )}
      </div>
    </div>
  );
}

const st = {
  loginBg: { height:'100vh', display:'flex', justifyContent:'center', alignItems:'center', background:'#f0f2f5' },
  card: { background:'white', padding:'40px', borderRadius:'20px', textAlign:'center', boxShadow:'0 10px 30px rgba(0,0,0,0.1)', width:'350px' },
  in: { display:'block', width:'100%', padding:'12px', margin:'10px 0', borderRadius:'10px', border:'1px solid #ddd', boxSizing:'border-box' },
  btn: { width:'100%', padding:'12px', background:'#2c3e50', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontWeight:'bold' },
  sidebar: { width:'240px', background:'#2c3e50', color:'white', padding:'30px', display:'flex', flexDirection:'column' },
  profile: { textAlign:'center', marginBottom:'40px', borderBottom:'1px solid #34495e', paddingBottom:'20px' },
  nav: { flex:1 },
  navBtn: { display:'block', width:'100%', padding:'12px', background:'transparent', border:'none', color:'#ecf0f1', textAlign:'left', cursor:'pointer', borderRadius:'8px', marginBottom:'5px' },
  out: { padding:'12px', background:'#e74c3c', color:'white', border:'none', borderRadius:'10px', cursor:'pointer' },
  grid: { display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(180px, 1fr))', gap:'20px' },
  classBox: { background:'white', padding:'25px', borderRadius:'15px', textAlign:'center', cursor:'pointer', boxShadow:'0 5px 15px rgba(0,0,0,0.05)' },
  addBtn: { background:'#3498db', color:'white', border:'none', padding:'5px 10px', borderRadius:'5px', marginTop:'10px', fontSize:'11px', cursor:'pointer' },
  whiteCard: { background:'white', padding:'30px', borderRadius:'20px' },
  backBtn: { background:'#eee', border:'none', padding:'8px 20px', borderRadius:'8px', cursor:'pointer' },
  table: { width:'100%', borderCollapse:'collapse' },
  thead: { background:'#2c3e50', color:'white' },
  tr: { borderBottom:'1px solid #eee', textAlign:'center', height:'70px' },
  pBtn: { background:'#2ecc71', color:'white', border:'none', padding:'4px 8px', borderRadius:'4px', cursor:'pointer' },
  aBtn: { background:'#e74c3c', color:'white', border:'none', padding:'4px 8px', borderRadius:'4px', cursor:'pointer' },
  miniIn: { width:'50px', padding:'5px', textAlign:'center' },
  stuCard: { background:'white', padding:'40px', borderRadius:'20px' },
  infoBox: { background:'#f8f9fa', padding:'10px 15px', borderRadius:'8px', border:'1px solid #eee', fontSize:'13px' },
  attGrid: { display:'grid', gridTemplateColumns:'repeat(7, 1fr)', gap:'8px', marginTop:'20px' },
  dayBox: { padding:'10px 0', textAlign:'center', borderRadius:'8px', border:'1px solid #eee', fontSize:'12px' }
};
